//! Minimal `no_std` parser for flattened device tree (DTB) blobs.
//!
//! The crate exposes a zero-allocation parser over an in-memory DTB and small
//! helper iterators for common properties such as `compatible`, `reg`, and
//! `ranges`.

#![no_std]
#![warn(missing_docs)]

#[cfg(feature = "alloc")]
extern crate alloc;

