/// A single entry from the DTB memory reservation table.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub struct MemoryReservation {
    /// Physical base address of the reserved region.
    pub address: u64,
    /// Size of the reserved region in bytes.
    pub size: u64,
}

/// Iterator over the DTB memory reservation table.
#[derive(Clone)]
pub struct MemoryReservations<'a> {
    blob: &'a [u8],
    cursor: usize,
    end: usize,
}

impl Iterator for MemoryReservations<'_> {
    type Item = MemoryReservation;

    fn next(&mut self) -> Option<Self::Item> {
        if self.cursor + 16 > self.end {
            return None;
        }
        let address = u64::from_be_bytes(
            self.blob
                .get(self.cursor..self.cursor + 8)?
                .try_into()
                .ok()?,
        );
        let size = u64::from_be_bytes(
            self.blob
                .get(self.cursor + 8..self.cursor + 16)?
                .try_into()
                .ok()?,
        );
        self.cursor += 16;
        if address == 0 && size == 0 {
            return None;
        }
        Some(MemoryReservation { address, size })
    }
}

/// Errors returned while validating or traversing a DTB blob.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum Error {
    /// The blob does not start with the DTB magic value.
    BadMagic,
    /// The blob ended before the requested data was fully available.
    Truncated,
    /// The blob contains invalid offsets, sizes, or overlapping regions.
    Bounds,
    /// The header declares a DTB version outside the supported range.
    UnsupportedVersion,
    /// The structure block contains an unexpected token.
    BadToken,
    /// A string field was not valid UTF-8.
    BadUtf8,
}

/// Parsed view over a validated DTB blob.
#[derive(Clone, Copy)]
pub struct Parser<'a> {
    blob: &'a [u8],
    header: Header,
}

impl<'a> Parser<'a> {
    /// Validates `blob` and returns a parser over its declared `totalsize`.
    pub fn new(blob: &'a [u8]) -> Result<Self, Error> {
        let header = Header::parse(blob)?;
        Ok(Self {
            blob: &blob[..header.totalsize as usize],
            header,
        })
    }

    /// Returns the parsed DTB header.
    pub fn header(&self) -> Header {
        self.header
    }

    /// Returns the validated DTB blob slice.
    pub fn blob(&self) -> &'a [u8] {
        self.blob
    }

    /// Iterates over entries from the memory reservation table.
    pub fn memory_reservations(&self) -> MemoryReservations<'a> {
        MemoryReservations {
            blob: self.blob,
            cursor: self.header.off_mem_rsvmap as usize,
            end: self.header.off_dt_struct as usize,
        }
    }

    /// Returns the root node of the structure block.
    pub fn root(&self) -> Result<Node<'a>, Error> {
        token::root(self.blob, self.header)
    }

    /// Traverses every node in depth-first order, including the root node.
    pub fn nodes(&self) -> search::AllNodes<'a> {
        search::AllNodes::new(self.blob, self.header)
    }

    /// Finds the first node whose `phandle` or `linux,phandle` matches `phandle`.
    pub fn find_by_phandle(&self, phandle: u32) -> Option<Node<'a>> {
        self.nodes().find(|node| node.phandle() == Some(phandle))
    }

    /// Resolves an entry from the `/aliases` node to its target path.
    pub fn resolve_alias(&self, alias: &str) -> Option<&'a str> {
        let root = self.root().ok()?;
        let aliases = root.find_child("aliases")?;
        aliases.property(alias)?.as_str().ok()
    }

    /// Iterates over nodes whose `compatible` property contains `needle`.
    pub fn find_compatible<'b>(&self, needle: &'b str) -> search::CompatibleIter<'a, 'b> {
        search::CompatibleIter::new(self.nodes(), needle)
    }

    /// Returns the effective `interrupt-parent` for a node path.
    ///
    /// The result is inherited from the root down through each path segment,
    /// with later definitions overriding earlier ones.
    pub fn inherited_interrupt_parent(&self, target_path: &str) -> Option<u32> {
        let root = self.root().ok()?;
        let mut result = root.interrupt_parent();
        let mut node = root;
        for segment in target_path.split('/').filter(|s| !s.is_empty()) {
            node = node.find_child(segment)?;
            if let Some(phandle) = node.interrupt_parent() {
                result = Some(phandle);
            }
        }
        result
    }

    /// Returns the effective `#address-cells` for a node path.
    ///
    /// Walks from root through each path segment, collecting the most
    /// recently declared `#address-cells` value (per the DTB inheritance
    /// rules). Returns `None` when the path cannot be resolved.
    pub fn inherited_address_cells(&self, target_path: &str) -> Option<u32> {
        let root = self.root().ok()?;
        let mut result = root.address_cells();
        let mut node = root;
        for segment in target_path.split('/').filter(|s| !s.is_empty()) {
            node = node.find_child(segment)?;
            if let Some(cells) = node.address_cells() {
                result = Some(cells);
            }
        }
        result
    }

    /// Returns the effective `#size-cells` for a node path.
    ///
    /// Walks from root through each path segment, collecting the most
    /// recently declared `#size-cells` value (per the DTB inheritance
    /// rules). Returns `None` when the path cannot be resolved.
    pub fn inherited_size_cells(&self, target_path: &str) -> Option<u32> {
        let root = self.root().ok()?;
        let mut result = root.size_cells();
        let mut node = root;
        for segment in target_path.split('/').filter(|s| !s.is_empty()) {
            node = node.find_child(segment)?;
            if let Some(cells) = node.size_cells() {
                result = Some(cells);
            }
        }
        result
    }

    /// Collects every compatible match into a `Vec`.
    #[cfg(feature = "alloc")]
    pub fn find_all_compatible(&self, needle: &str) -> alloc::vec::Vec<Node<'a>> {
        self.find_compatible(needle).collect()
    }

    /// Reconstructs the absolute path for `node`.
    ///
    /// Returns `None` when `node` did not originate from this parser.
    #[cfg(feature = "alloc")]
    pub fn path_of(&self, node: &Node<'a>) -> Option<alloc::string::String> {
        use alloc::string::String;

        // Reject nodes from a different blob (different backing allocation).
