use proc_macro::TokenStream;
use quote::quote;
use syn::{ItemFn, parse_macro_input};

/// Attribute macro: `#[scarlet_test]`
///
/// Transforms a test function by adding a `TestEntry` in the `.scarlet_tests`
/// linker section so the runner discovers it with its name at runtime.
///
/// ```ignore
/// #[scarlet_test]
/// fn my_test() {
///     assert_eq!(1 + 1, 2);
/// }
/// ```
#[proc_macro_attribute]
pub fn scarlet_test(_attr: TokenStream, item: TokenStream) -> TokenStream {
    let input = parse_macro_input!(item as ItemFn);
    let fn_name = &input.sig.ident;
    let static_name = quote::format_ident!("__scarlet_test_{}", fn_name);

    let expanded = quote! {
        #input

        #[used]
        #[unsafe(link_section = ".scarlet_tests")]
        #[allow(non_upper_case_globals)]
        static #static_name: crate::test::TestEntry = crate::test::TestEntry {
            name: stringify!(#fn_name),
            func: #fn_name,
        };
    };

    TokenStream::from(expanded)
}

