const RISCV64_LINKER_SCRIPT: &str = r#"
OUTPUT_ARCH(riscv)
ENTRY(_start)

BASE_ADDRESS = 0x80200000;

SECTIONS
{
    . = BASE_ADDRESS;

    _skernel = .;

    .text : {
        _stext = .;
        *(.text.entry)
        . = ALIGN(4K);
        _strampoline = .;
        *(.trampoline)
        . = ALIGN(4K);
        _etrampoline = .;
        *(.text .text.*)
        _etext = .;
    }

    .rodata : ALIGN(4K) {
        _srodata = .;
        *(.rodata .rodata.*)
        *(.srodata .srodata.*)
        _erodata = .;
    }

    .data : ALIGN(4K) {
        _sdata = .;
        *(.data .data.*)
        *(.sdata .sdata.*)
        _edata = .;
    }

    .scarlet_tests : ALIGN(8) {
        _stests = .;
        KEEP(*(.scarlet_tests))
        _etests = .;
    }

    .bss : ALIGN(4K) {
        _sbss = .;
        . = ALIGN(4K);
        . += 4K;
        *(.bss.stack)
        . = ALIGN(4K);
        *(.bss .bss.*)
        *(.sbss .sbss.*)
        _ebss = .;
    }

    _ekernel = .;

    /DISCARD/ : {
        *(.eh_frame)
    }
}
"#;

