pub trait IrqChip: Send + Sync {
    /// Mask (disable) a hardware IRQ line.
    fn mask(&self, hwirq: u32) -> Result<(), IrqError> {
        Ok(())
    }
    /// Unmask (enable) a hardware IRQ line.
    fn unmask(&self, hwirq: u32) -> Result<(), IrqError> {
        Ok(())
    }
    /// Claim the next pending interrupt for this hart. Returns None if none.
    fn claim(&self) -> Option<u32>;
    /// End-of-interrupt: signal processing complete.
    fn eoi(&self, hwirq: u32);
    /// Get priority of a hardware IRQ line.
    fn get_priority(&self, hwirq: u32) -> u8 {
        0
    }
    /// Set priority of a hardware IRQ line.
    fn set_priority(&self, _hwirq: u32, _priority: u8) {}
    /// Set affinity mask for an IRQ.
    fn set_affinity(&self, _hwirq: u32, _mask: &HartMask) {}
    /// Unique small integer ID for this chip, assigned at boot.
    fn chip_id(&self) -> u8;
    /// First Linux IRQ number in this chip's domain.
    fn domain_base(&self) -> u32;
    /// Maximum number of hardware IRQs this chip supports.
    fn irq_count(&self) -> u32 {
        MAX_IRQS_PER_CHIP as u32
    }
}

// ---------------------------------------------------------------------------
// IrqDesc — per-IRQ descriptor
// ---------------------------------------------------------------------------

const MAX_IRQS: usize = 128;
const MAX_CHIPS: usize = 4;
const MAX_IRQS_PER_CHIP: usize = 64;
const INVALID_IRQ: u32 = u32::MAX;

pub type IrqHandler = fn();

pub struct IrqDesc {
    pub handler: Option<IrqHandler>,
    pub name: Option<&'static str>,
    pub chip: Option<&'static dyn IrqChip>,
    pub hwirq: u32,
    pub count: AtomicU64,
    pub affinity: HartMask,
    pub target_cursor: AtomicUsize,
}

static IRQ_DESC_TABLE: SyncUnsafeCell<[IrqDesc; MAX_IRQS]> = unsafe { core::mem::zeroed() };

static IRQ_REVERSE_MAP: SyncUnsafeCell<[[u32; MAX_IRQS_PER_CHIP]; MAX_CHIPS]> =
    SyncUnsafeCell::new([[INVALID_IRQ; MAX_IRQS_PER_CHIP]; MAX_CHIPS]);

fn irq_desc_table() -> &'static [IrqDesc; MAX_IRQS] {
    unsafe { &*IRQ_DESC_TABLE.get() }
}

fn irq_desc_table_mut() -> &'static mut [IrqDesc; MAX_IRQS] {
    unsafe { &mut *IRQ_DESC_TABLE.get() }
}

fn reverse_irq_lookup(chip: &dyn IrqChip, hwirq: u32) -> Option<u32> {
    let chip_id = chip.chip_id() as usize;
    let hw = hwirq as usize;
    if chip_id >= MAX_CHIPS || hw >= MAX_IRQS_PER_CHIP {
        return None;
    }
    let map = unsafe { &*IRQ_REVERSE_MAP.get() };
    match map[chip_id][hw] {
        INVALID_IRQ => None,
        irq => Some(irq),
    }
}

fn set_reverse_map(chip_id: u8, hwirq: u32, linux_irq: u32) {
    let map = unsafe { &mut *IRQ_REVERSE_MAP.get() };
    map[chip_id as usize][hwirq as usize] = linux_irq;
}

// ---------------------------------------------------------------------------
// IrqDomain
// ---------------------------------------------------------------------------

pub struct IrqDomain {
    base: u32,
    count: u32,
    name: &'static str,
}

impl IrqDomain {
    pub fn new_linear(base: u32, count: u32, name: &'static str) -> Result<Self, IrqError> {
        if base as usize + count as usize > MAX_IRQS {
            return Err(IrqError::InvalidIrq);
        }
        Ok(Self { base, count, name })
    }

    pub fn map_hwirq(
        &self,
        hwirq: u32,
        chip: &'static dyn IrqChip,
        handler: IrqHandler,
        name: &'static str,
    ) -> Result<u32, IrqError> {
        if hwirq >= self.count {
            return Err(IrqError::InvalidHwirq);
        }
        if chip.chip_id() as usize >= MAX_CHIPS
            || hwirq >= chip.irq_count()
            || hwirq as usize >= MAX_IRQS_PER_CHIP
        {
            return Err(IrqError::InvalidHwirq);
        }
        let irq = self.base + hwirq;
        let table = irq_desc_table_mut();
        let desc = &mut table[irq as usize];
        if desc.handler.is_some() {
            return Err(IrqError::AlreadyRegistered);
        }
        desc.handler = Some(handler);
        desc.name = Some(name);
        desc.chip = Some(chip);
        desc.hwirq = hwirq;
        set_reverse_map(chip.chip_id(), hwirq, irq);
        Ok(irq)
    }
}

// ---------------------------------------------------------------------------
// Errors
// ---------------------------------------------------------------------------

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum IrqError {
    AlreadyRegistered,
    InvalidHwirq,
    InvalidIrq,
    Unsupported,
}

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

/// IRQ registration is done exclusively through IrqDomain::map_hwirq,
/// which fills all descriptor fields (handler, name, chip, hwirq)
/// and populates the reverse map. There is no standalone request_irq.

pub fn free_irq(irq: u32) -> Result<(), IrqError> {
    let table = irq_desc_table_mut();
    let desc = table.get_mut(irq as usize).ok_or(IrqError::InvalidIrq)?;
    desc.handler = None;
    desc.name = None;
    Ok(())
}

pub fn enable_irq(irq: u32) {
    let desc = match irq_desc_table().get(irq as usize) {
        Some(d) if d.chip.is_some() => d,
        _ => return,
    };
    let _ = desc.chip.unwrap().unmask(desc.hwirq);
}

pub fn disable_irq(irq: u32) {
    let desc = match irq_desc_table().get(irq as usize) {
        Some(d) if d.chip.is_some() => d,
        _ => return,
    };
    let _ = desc.chip.unwrap().mask(desc.hwirq);
}

pub fn irq_set_affinity(irq: u32, mask: &HartMask) -> Result<(), IrqError> {
    let table = irq_desc_table_mut();
    let desc = table.get_mut(irq as usize).ok_or(IrqError::InvalidIrq)?;
    desc.affinity = *mask;
    if let Some(chip) = desc.chip {
        chip.set_affinity(desc.hwirq, mask);
    }
    Ok(())
}

// ---------------------------------------------------------------------------
// Dispatch
// ---------------------------------------------------------------------------

/// Platform parent chip, set by arch init (PLIC or EIOINTC).
static mut PARENT_CHIP: Option<&'static dyn IrqChip> = None;

/// Set the parent chip during platform init. Called once, before IRQs are enabled.
pub fn set_parent_chip(chip: &'static dyn IrqChip) {
    unsafe {
        PARENT_CHIP = Some(chip);
    }
}

/// Handle an external interrupt on the current hart. Called from trap dispatch.
pub fn handle_external(_frame: &mut TrapFrame) {
    let chip = match unsafe { PARENT_CHIP } {
        Some(c) => c,
        None => return,
    };

    let Some(hwirq) = chip.claim() else {
        return;
    };

    let Some(irq) = reverse_irq_lookup(chip, hwirq) else {
        chip.eoi(hwirq);
        return;
    };

    let Some(desc) = irq_desc_table().get(irq as usize) else {
        chip.eoi(hwirq);
        return;
    };
    let desc_chip = desc.chip.unwrap_or(chip);
    desc.count.fetch_add(1, Ordering::Relaxed);

    if let Some(handler) = desc.handler {
        handler();
    }

    desc_chip.eoi(desc.hwirq);
}

